import { useState } from "react";
import { Task } from "../gestor/page";

interface Props {
  tareas: Task[];
}
export function CardTareas({ tareas }: Props) {
  const [seeMore, setSeeMore] = useState("");
  const completado = tareas.filter(
    (task: Task) => task.estado === "completado",
  );
  const pendiente = tareas.filter((task: Task) => task.estado === "pendiente");
  const finalizado = tareas.filter(
    (task: Task) => task.estado === "finalizado",
  );

  return (
    <div>
      <li>
        <h2>Completado</h2>
        <p>{completado.length}</p>
        <button onClick={() => setSeeMore("completado")}>Ver más</button>
      </li>
      <li>
        <h2>Pendiente</h2>
        <p>{pendiente.length}</p>
        <button onClick={() => setSeeMore("pendiente")}>Ver más</button>
      </li>
      <li>
        <h2>Finalizado</h2>
        <p>{finalizado.length}</p>
        <button onClick={() => setSeeMore("finalizado")}>Ver más</button>
      </li>
    </div>
  );
}
